interface ThemeInterface<T> {
  getInstance(): T,
  setColorScheme(): void,
  subscribe(): void,
  publish(): void
}

type Store = {
  instance: any,
  element: HTMLElement | null,
  subscriber: Array<Function>
}

const store: Store = {
  instance: undefined,
  element: document.querySelector("huanlin-app #app"),
  subscriber: [] 
}

class Theme {
  private constructor() {

  }
  static getInstance(): Theme {
    if (!store.instance) {
      store.instance = Theme
    }
    return store.instance
  }
  static setColorScheme(mode) {
    if (mode === "dark") {
      store.element?.classList.add("dark")
    } else if (mode === "light") {
      store.element?.classList.remove("dark")
    }
    this.publish()
  }
  static subscribe(fn) {
    store.subscriber.push(fn)
    return this.unsubscribe(fn)
  }
  private static unsubscribe(fn) {
    return function() {
      const index = store.subscriber.findIndex(fn)
      store.subscriber.splice(index, 1)
    }
  }
  static setElement(element) {
    return store.element = element
  }
  static setSubscriber(subscriber) {
    return store.subscriber = subscriber
  }
  static getElement() {
    return store.element
  }
  static getSubscriber() {
    return store.subscriber 
  }
  static getStore() {
    return store
  }
  private static publish() {
    store.subscriber.forEach(fn => fn())
  }
}
export default Theme.getInstance()